const apt = $node['loop_appointments'].json;
const customer_name = apt.name || 'Valued Customer';
const service = apt.service || 'Appointment';
const time = apt.time_start;

const message = `Hi ${customer_name}! This is a reminder that you have a ${service} appointment tomorrow at ${time}. Please confirm or let us know if you need to reschedule.`;

return {
  phone: apt.phone,
  message: message,
  apt_id: apt.id,
  tenant_id: apt.tenant_id
};
